// App.js principal
import { NavigationContainer } from '@react-navigation/native';
import { createBottomTabNavigator } from '@react-navigation/bottom-tabs';
import AccueilScreen from './screens/AccueilScreen';
import PanierScreen from './screens/PanierScreen';
import CatalogueStack from './navigation/CatalogueStack';
import ProfilStack from './navigation/ProfilStack';

const Tab = createBottomTabNavigator();

export default function App() {
  return (
    &lt;NavigationContainer&gt;
      &lt;Tab.Navigator&gt;
        &lt;Tab.Screen name="Accueil" component={AccueilScreen} /&gt;
        &lt;Tab.Screen name="Catalogue" component={CatalogueStack} /&gt;
        &lt;Tab.Screen name="Panier" component={PanierScreen} /&gt;
        &lt;Tab.Screen name="Profil" component={ProfilStack} /&gt;
      &lt;/Tab.Navigator&gt;
    &lt;/NavigationContainer&gt;
  );
}

Erreurs identifiées :
1. Dans App.js, le Stack.Navigator est manquant. Les Stack.Screen doivent être enfants de Stack.Navigator.
2. Dans Accueil.js, le nom de l'écran est 'Profil' mais la navigation utilise 'Profile' (faute d'orthographe).

Code corrigé :
// App.js
function App() {
  return (
    &lt;NavigationContainer&gt;
      &lt;Stack.Navigator&gt;
        &lt;Stack.Screen name="Accueil" component={Accueil} /&gt;
        &lt;Stack.Screen name="Profil" component={Profil} /&gt;
      &lt;/Stack.Navigator&gt;
    &lt;/NavigationContainer&gt;
  );
}

// Accueil.js
&lt;Button title="Aller au profil" onPress={() => navigation.navigate('Profil')} /&gt;

1. navigation.goBack() - Retour à l'écran précédent
   navigation.goBack();

2. navigation.pop() - Retour à l'écran précédent (équivalent)
   navigation.pop();

3. navigation.popToTop() - Retour au premier écran de la pile
   navigation.popToTop();

4. navigation.navigate('Accueil') - Navigation explicite avec paramètres
   navigation.navigate('Accueil');

Méthode recommandée : navigation.goBack() car elle ne nécessite pas de connaître le nom de l'écran précédent.
